def main():
    with open(PROMPTS_PATH, "r", encoding="utf-8") as f:
        prompts_doc = json.load(f)

    trials_out = []
    for t in prompts_doc["trials"]:
        tid = t["trial_id"]
        if tid not in RESPONSES:
            raise SystemExit(f"missing response for trial {tid}")
        response, score, rationale = RESPONSES[tid]
        trials_out.append(
            {
                "trial_id": tid,
                "domain": t["domain"],
                "case_id": t["case_id"],
                "condition": "coe_r_scrambled",
                "seed": t["seed"],
                "prompt": t["prompt"],
                "response": response,
                "score": score,
                "score_rationale": rationale,
            }
        )

    # Aggregate stats
    scores = [t["score"] for t in trials_out]
    overall = sum(scores) / len(scores)
    by_domain = {}
    for t in trials_out:
        by_domain.setdefault(t["domain"], []).append(t["score"])
    domain_means = {d: sum(s) / len(s) for d, s in by_domain.items()}

    out = {
        "experiment": "coe_r_scrambled_control",
        "design": prompts_doc["design"],
        "summary": {
            "n_trials": len(trials_out),
            "overall_mean_score": round(overall, 4),
            "by_domain_mean": {d: round(v, 4) for d, v in domain_means.items()},
            "baseline_coe_r_overall": 3.75,
            "baseline_coe_r_by_domain": {
                "symmetry": 4.0,
                "knot_theory": 4.0,
                "graph_connectivity": 4.0,
                "boundary_interior": 4.0,
                "discrete_curvature": 4.0,
                "projection": 4.0,
                "surface_topology": 3.0,
                "surface_topology_s21": 3.0,
            },
            "delta_overall": round(overall - 3.75, 4),
        },
        "trials": trials_out,
    }
    OUT_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(OUT_PATH, "w", encoding="utf-8") as f:
        json.dump(out, f, ensure_ascii=False, indent=2)

    print(f"Wrote {len(trials_out)} trials to {OUT_PATH}")
    print(f"Overall mean: {overall:.4f}  (baseline CoE-R: 3.75, delta {overall-3.75:+.4f})")
    print("By domain:")
    for d, m in domain_means.items():
        print(f"  {d:30s}: {m:.4f}  (baseline {out['summary']['baseline_coe_r_by_domain'][d]:.2f})")


if __name__ == "__main__":
    main()
